mapper.update:
UPDATE lecture
SET rem_std = rem_std + 1
WHERE lecture_id = #{lectureId}

mapper.select:
SELECT CEIL(COUNT(l.lecture_id) / #{size}) AS maxPage, COUNT(l.lecture_id) AS totalCount FROM lecture l LEFT JOIN major mj ON l.major_id = mj.major_id
l.year = YEAR(CURDATE()) AND l.status = 'approved'
AND l.type = #{lectureType}
AND l.academic_year = #{academicYear}
AND mj.name LIKE CONCAT('%', #{majorName}, '%')
AND l.name LIKE CONCAT('%', #{lectureName}, '%')
